const body = $input.first().json.body;

if (!body._id) throw new Error('Campo _id é obrigatório para editar um imóvel.');

// Campos editáveis — inclui apenas os que foram enviados no payload
const campos = ['titulo', 'status', 'preco', 'precoCondominio', 'finalidade',
  'tipo', 'quartos', 'suites', 'banheiros', 'vagas', 'areaUtil', 'areaTotal',
  'andar', 'descricao', 'endereco', 'destaque', 'metaTitle', 'metaDescription'];

const set = {};
for (const campo of campos) {
  if (body[campo] !== undefined) {
    // Converte números
    const numericos = ['preco','precoCondominio','quartos','suites','banheiros','vagas','areaUtil','areaTotal','andar'];
    set[campo] = numericos.includes(campo) ? Number(body[campo]) : body[campo];
  }
}

// Referências
if (body.bairroId) set['bairro'] = { _type: 'reference', _ref: body.bairroId };
if (body.condominioId) set['condominio'] = { _type: 'reference', _ref: body.condominioId };

return [{
  json: {
    mutations: [
      {
        patch: {
          id: body._id,
          set: set
        }
      }
    ]
  }
}];
